#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;
    vector<vector<int>> adj(N, vector<int>(N, 0));
    int M = 3 * N / 2;
    for (int i = 0; i < M; i++) {
        int a, b;
        cin >> a >> b;
        a--; b--;
        adj[a][b] = adj[b][a] = 1;
    }

    // Precompute positions 0..N-1
    vector<int> perm(N);
    iota(perm.begin(), perm.end(), 0);

    const int INF = 1e9;
    int best = INF;

    // Try all permutations of cows to stalls (positions)
    do {
        int total = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (adj[perm[i]][perm[j]]) {
                    total += j - i;
                }
            }
        }
        best = min(best, total);
    } while (next_permutation(perm.begin(), perm.end()));

    cout << best << '\n';
    return 0;
}
